using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tarefa #35 — Sistema de Loja: promoção de horário aplicada a uma
/// <see cref="ShopEntry"/>. Enquanto <see cref="WorldState.CurrentTimeOfDay"/>
/// estiver em <see cref="activeDuring"/>, o preço-base do item recebe um
/// desconto de <see cref="discountPercent"/>%.
/// </summary>
[System.Serializable]
public class ShopPromotion
{
    [Tooltip("Horas do dia em que esta promoção está activa (WorldState.CurrentTimeOfDay, alimentado por DayNightCycle2D).")]
    public List<TimeOfDay> activeDuring = new List<TimeOfDay>();

    [Tooltip("Desconto aplicado ao preço-base durante estas horas (0-100%). Ex: 25 = -25%.")]
    [Range(0, 100)] public int discountPercent = 0;
}

/// <summary>
/// Tarefa #35 — uma entrada de inventário de uma <see cref="ShopData"/>: o
/// item à venda, o seu preço (padrão ou personalizado), em que horas do dia
/// está disponível, e eventuais promoções de horário.
/// </summary>
[System.Serializable]
public class ShopEntry
{
    [Tooltip("Item à venda nesta loja.")]
    public ItemData item;

    [Tooltip("Se activo, usa 'customPrice' em vez do preço padrão do item (ItemData.buyPrice).")]
    public bool useCustomPrice;

    [Tooltip("Preço personalizado (Sementes), usado apenas se 'useCustomPrice' estiver activo.")]
    [Min(0)] public int customPrice;

    [Tooltip("Se não vazio, este item só aparece à venda durante estas horas do dia (ex: item nocturno).")]
    public List<TimeOfDay> availableDuring = new List<TimeOfDay>();

    [Tooltip("Promoções de horário (descontos) aplicadas ao preço-base deste item.")]
    public List<ShopPromotion> promotions = new List<ShopPromotion>();

    /// <summary>Preço-base (antes de promoções): 'customPrice' se 'useCustomPrice', senão ItemData.buyPrice.</summary>
    public int BasePrice => useCustomPrice ? customPrice : (item != null ? item.buyPrice : 0);

    /// <summary>True se este item deve aparecer à venda na hora actual do mundo (WorldState.CurrentTimeOfDay).</summary>
    public bool IsAvailableNow()
    {
        if (availableDuring == null || availableDuring.Count == 0) return true;

        var time = CurrentTime();
        return availableDuring.Contains(time);
    }

    /// <summary>True se alguma promoção com desconto > 0 estiver activa na hora actual.</summary>
    public bool HasActivePromotion()
    {
        if (promotions == null) return false;

        var time = CurrentTime();
        foreach (var promo in promotions)
        {
            if (promo == null || promo.discountPercent <= 0) continue;
            if (promo.activeDuring != null && promo.activeDuring.Contains(time)) return true;
        }

        return false;
    }

    /// <summary>Preço final (Sementes), já com o maior desconto de promoção activa aplicado (descontos não se acumulam).</summary>
    public int GetCurrentPrice()
    {
        int basePrice = BasePrice;
        int bestDiscount = 0;

        if (promotions != null)
        {
            var time = CurrentTime();
            foreach (var promo in promotions)
            {
                if (promo == null) continue;
                if (promo.activeDuring != null && promo.activeDuring.Contains(time))
                    bestDiscount = Mathf.Max(bestDiscount, promo.discountPercent);
            }
        }

        return Mathf.Max(0, Mathf.RoundToInt(basePrice * (1f - bestDiscount / 100f)));
    }

    private static TimeOfDay CurrentTime() =>
        WorldState.Instance != null ? WorldState.Instance.CurrentTimeOfDay : TimeOfDay.Manha;
}

/// <summary>
/// Tarefa #35 — Sistema de Loja: define o inventário, preços/promoções e a
/// configuração de recompra de uma loja, para usar com
/// <see cref="Action_OpenShop"/> (Eventos de NPC) e <see cref="ShopUI"/>.
///
/// - Compra (jogador → loja): cada <see cref="ShopEntry"/> usa o preço padrão
///   do item (ItemData.buyPrice) ou um preço personalizado, com possíveis
///   promoções/restrições de horário (ligadas a WorldState.CurrentTimeOfDay,
///   alimentado por DayNightCycle2D).
/// - Venda (jogador → loja, "recompra"): se <see cref="merchantBuysItems"/>
///   estiver activo, o vendedor compra qualquer item com
///   ItemData.sellable == true por <see cref="buybackMultiplier"/> × ItemData.sellPrice
///   (por omissão, metade do valor — GetBuybackPrice).
/// - Tesouros (ItemType.Tesouro): categoria de itens vendáveis e trocáveis
///   por Sementes — funcionam como qualquer item "sellable" na recompra
///   acima; não precisam de tratamento especial além de
///   sellable = true e sellPrice definido.
/// </summary>
[CreateAssetMenu(menuName = "Animals/Shop Data", fileName = "NewShop")]
public class ShopData : ScriptableObject
{
    [Header("Identidade")]
    public string shopName = "Loja";

    [Header("Inventário")]
    [Tooltip("Itens à venda nesta loja (preço, disponibilidade e promoções por entrada).")]
    public List<ShopEntry> entries = new List<ShopEntry>();

    [Header("Recompra (vendedor compra itens do jogador)")]
    [Tooltip("Se activo, o jogador pode vender a este vendedor qualquer item com ItemData.sellable == true (incluindo Tesouros).")]
    public bool merchantBuysItems = false;

    [Tooltip("Fracção do ItemData.sellPrice paga ao jogador na recompra. Por omissão, 0.5 = 'sempre pela metade do valor'.")]
    [Range(0f, 1f)] public float buybackMultiplier = 0.5f;

    /// <summary>
    /// Preço (Sementes) pago ao jogador ao vender "item" a esta loja, ou 0 se
    /// a loja não compra itens, o item for null, ou ItemData.sellable for
    /// false.
    /// </summary>
    public int GetBuybackPrice(ItemData item)
    {
        if (!merchantBuysItems || item == null || !item.sellable) return 0;
        return Mathf.Max(1, Mathf.RoundToInt(item.sellPrice * buybackMultiplier));
    }
}
